import{_ as a,o as s,c as t,a1 as r}from"./chunks/framework.BX4nIuL2.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/6laser_cutter/Safety.md","filePath":"courses/fab-course/doc/6laser_cutter/Safety.md"}'),n={name:"courses/fab-course/doc/6laser_cutter/Safety.md"};function l(o,e,i,c,h,d){return s(),t("div",null,[...e[0]||(e[0]=[r('<h2 id="_1-laser-safety" tabindex="-1">1. Laser safety <a class="header-anchor" href="#_1-laser-safety" aria-label="Permalink to &quot;1. Laser safety&quot;">​</a></h2><p>Most types of lasers operating in the visible and near infrared regions are sufficiently intense as to represent a hazard to the eye. Although damage may be caused to all parts of the eyes, the most vulnerable part is the retina, on which the beam may be focussed by the eye lens resulting in the destruction of tissues and the creation of permanent blind spots. High power lasers can also damage the skin. Only trained peaple can operate the machine, and we must close the enclosure before run the machine.</p><h2 id="_2-laser-classes" tabindex="-1">2. Laser classes <a class="header-anchor" href="#_2-laser-classes" aria-label="Permalink to &quot;2. Laser classes&quot;">​</a></h2><p>The current laser classes in national laser classes are: 1, 2, 3A, 3B and 4. The class of each laser must be marked clearly by the supplier.</p><ul><li>Class 1:It is safe in the reasonable working condition, and no specific safety controls are required.</li><li>Class 2: Wavelength range from 400nm to 700nm, visible lasers</li><li>Class 3A: Lower risk than 3B, but direct viewing of beam usually safe</li><li>Class 3B: Intrabeam viewing not safe to the eye, diffusely reflected beam usually safe to the eye, assumed to be safe to the skin.</li><li>Class 4: Those that generate the hazardous diffusely reflected beam, which may be harmful to the eye or skin, and can present a fire hazard.</li></ul><p>During normal operation, the machine is enclosed and laser classification is Class 1. In normal usage the interlocked machine does not allow exposure to any dangerous laser radiation. The cutting chamber is fully enclosed during standard operation and keys are needed to access all body panels that open. <a href="http://www.nottingham.edu.cn/en/ehs/laser-safety.aspx" target="_blank" rel="noreferrer">In school&#39;s safety rule</a>,laser operator need wear normal PPE (Laboratory coat, Safety glasses, Dust mask).</p><h2 id="_3-reference" tabindex="-1">3. Reference <a class="header-anchor" href="#_3-reference" aria-label="Permalink to &quot;3. Reference&quot;">​</a></h2><ul><li><a href="https://www.nottingham.edu.cn/en/ehs/laser-safety.aspx" target="_blank" rel="noreferrer">Nottingham laser safety</a></li></ul>',8)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
